export function isToday(date: Date | string | null | undefined): boolean {
  if (!date) return false;

  const inputDate = typeof date === "string" ? new Date(date) : date;
  const today = new Date();

  // Compare year, month, and day
  return (
    inputDate.getFullYear() === today.getFullYear() &&
    inputDate.getMonth() === today.getMonth() &&
    inputDate.getDate() === today.getDate()
  );
}

export function getTodayStart(): Date {
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  return today;
}

export function getTodayEnd(): Date {
  const today = new Date();
  today.setHours(23, 59, 59, 999);
  return today;
}

export function isConversationFromToday(
  conversationDate: Date | string | null | undefined
): boolean {
  return isToday(conversationDate);
}

export function formatDateForDailyConversation(date: Date = new Date()): string {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");
  return `${year}-${month}-${day}`;
}

export function getDailyGreeting(name: string, dayOfWeek: number): string {
  const dayNames = [
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday",
  ];

  const dayName = dayNames[dayOfWeek];

  const greetings: Record<number, string> = {
    0: `Welcome back, ${name}! It's Sunday - a perfect day to plan your week ahead. I'm here to help you get organized.`,
    1: `Welcome back, ${name}! It's Monday and I'm here to help you tackle the week ahead. Let's make it a productive one!`,
    2: `Welcome back, ${name}! It's Tuesday - you're already making progress this week. I'm here to keep you on track.`,
    3: `Welcome back, ${name}! It's Wednesday - you're halfway through the week! I'm here to help you stay focused.`,
    4: `Welcome back, ${name}! It's Thursday - almost there! I'm here to help you finish the week strong.`,
    5: `Welcome back, ${name}! It's Friday - let's finish the week on a high note! I'm here to help you wrap things up.`,
    6: `Welcome back, ${name}! It's Saturday - time to catch up and plan ahead. I'm here to help you stay organized.`,
  };

  return greetings[dayOfWeek] || `Welcome back, ${name}! It's ${dayName} and I'm here to help you accomplish your goals.`;
}

export function getCurrentDayOfWeek(): number {
  return new Date().getDay();
}

export function formatTime(timeString: string): string {
  if (!timeString) return "";
  
  const [hours, minutes] = timeString.split(":").map(Number);
  const period = hours >= 12 ? "PM" : "AM";
  const displayHours = hours % 12 || 12;
  const displayMinutes = minutes.toString().padStart(2, "0");
  
  return `${displayHours}:${displayMinutes} ${period}`;
}

export function getDayName(date: Date): string {
  return date.toLocaleDateString("en-US", { weekday: "long" });
}

export function getShortDayName(date: Date): string {
  return date.toLocaleDateString("en-US", { weekday: "short" });
}

export function getStartOfWeek(date: Date): Date {
  const d = new Date(date);
  const day = d.getDay();
  const diff = d.getDate() - day + (day === 0 ? -6 : 1); // Adjust when day is Sunday
  return new Date(d.setDate(diff));
}

export function getUserTimezone(preferences?: { timezone?: string | null } | null): string {
  if (preferences?.timezone) {
    return preferences.timezone;
  }
  
  // Fallback to browser timezone
  try {
    return Intl.DateTimeFormat().resolvedOptions().timeZone;
  } catch {
    return "America/New_York"; // Final fallback
  }
}

export function getTodayStartInTimezone(timezone: string): Date {
  const now = new Date();
  
  // Get what "today" is in the user's timezone
  const formatter = new Intl.DateTimeFormat("en-US", {
    timeZone: timezone,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
  });
  
  const parts = formatter.formatToParts(now);
  const year = parseInt(parts.find(p => p.type === "year")?.value || "0");
  const month = parseInt(parts.find(p => p.type === "month")?.value || "0") - 1;
  const day = parseInt(parts.find(p => p.type === "day")?.value || "0");
  
  // Create a date representing midnight in the timezone
  // We need to construct a date that, when formatted in the timezone, gives us midnight
  // The trick: create a date string and use Intl to convert it
  const dateStr = `${year}-${String(month + 1).padStart(2, "0")}-${String(day).padStart(2, "0")}T00:00:00`;
  
  // Use a more reliable method: create a date and find what UTC time corresponds to midnight in the timezone
  // We'll use the fact that we can format a UTC date in the timezone to see what it represents
  const testUtc = new Date(`${dateStr}Z`); // UTC midnight for that date
  
  // Format this UTC date in the timezone to see what time it represents there
  const tzFormatter = new Intl.DateTimeFormat("en-US", {
    timeZone: timezone,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  });
  
  const tzParts = tzFormatter.formatToParts(testUtc);
  const tzHour = parseInt(tzParts.find(p => p.type === "hour")?.value || "0");
  const tzMinute = parseInt(tzParts.find(p => p.type === "minute")?.value || "0");
  
  // Calculate the offset
  const offsetMinutes = (tzHour * 60 + tzMinute);
  
  // Adjust the UTC date to represent midnight in the timezone
  const midnightUtc = new Date(testUtc.getTime() - offsetMinutes * 60 * 1000);
  
  return midnightUtc;
}

export function getTodayEndInTimezone(timezone: string): Date {
  const start = getTodayStartInTimezone(timezone);
  const end = new Date(start);
  // Add 23 hours, 59 minutes, 59 seconds, 999 milliseconds
  end.setTime(start.getTime() + 24 * 60 * 60 * 1000 - 1);
  return end;
}

